const LOCALES = {de:'de-DE',en:'en-GB',fr:'fr-FR',es:'es-ES',nl:'nl-NL'};

function getLang(){return localStorage.getItem('uhl_lang')||'de';}
function setLang(lang){localStorage.setItem('uhl_lang',lang);applyTranslations();}
function getLocale(){return LOCALES[getLang()]||'de-DE';}
function t(key){const l=getLang();return(TRANSLATIONS[l]&&TRANSLATIONS[l][key])||TRANSLATIONS['de'][key]||key;}

function applyTranslations(){
  const lang=getLang();
  document.documentElement.lang=lang;
  document.title=t('page.title');
  document.querySelectorAll('.lang-btn').forEach(btn=>{
    btn.classList.toggle('active',btn.dataset.lang===lang);
  });
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const v=t(el.dataset.i18n); if(v) el.textContent=v;
  });
  document.querySelectorAll('[data-i18n-html]').forEach(el=>{
    const v=t(el.dataset.i18nHtml); if(v) el.innerHTML=v;
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>{
    const v=t(el.dataset.i18nPlaceholder); if(v) el.placeholder=v;
  });
  document.querySelectorAll('[data-i18n-title]').forEach(el=>{
    const v=t(el.dataset.i18nTitle); if(v) el.title=v;
  });
  const hd=document.getElementById('headerDate');
  if(hd) hd.textContent=new Date().toLocaleDateString(getLocale(),{day:'2-digit',month:'2-digit',year:'numeric'});
  if(typeof buildLigaLabelSection==='function') buildLigaLabelSection();
  if(typeof buildSponsoringUI==='function') buildSponsoringUI();
  if(typeof buildUmsatzUI==='function') buildUmsatzUI();
  if(typeof opRenderResult==='function'&&window._lastResults) opRenderResult();
}
